#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int id,n,a[N],dp[N],ans;
vector<int> g[N];
struct node
{
    int num,id;
} b[N];
bool cmp(node x,node y)
{
    return x.num<y.num;
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        b[i].num=a[i];
        b[i].id=i;
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        cin>>x>>y;
        g[x].push_back(y);
        g[y].push_back(x);
    }
    sort(b+1,b+1+n,cmp);
    for(int i=1;i<=n;i++)
    {
        int idd=b[i].id;
        for(int j=0;j<g[idd].size();j++)
        {
            int v=g[idd][j];
            if(a[v]<b[i].num)
            {
                dp[idd]+=dp[v];
            }
        }
        dp[idd]++;
        ans=max(ans,dp[idd]);
    }
    cout<<ans;
    return 0;
}
